/* Build an anchor-positioned tooltip system:
   - Button establishes an anchor with anchor-name
   - Tooltip positions itself relative to the anchor
   - Use position-anchor and anchor() functions
   - Note marker creates a second anchor with its footnote */
.anchor-demo {
  padding: 60px 40px;
  min-height: 200px;
}

referenceSolutions:
.anchor-demo {
  padding: 60px 40px;
  min-height: 200px;
}
.anchor-btn {
  padding: 10px 20px;
  background-color: rgb(0, 123, 255);
  color: rgb(255, 255, 255);
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-size: 14px;
}
.anchor-tooltip {
  position: fixed;
  position-anchor: --btn-anchor;
  top: anchor(bottom);
  left: anchor(center);
  translate: -50% 8px;
  background-color: rgb(33, 37, 41);
  color: rgb(255, 255, 255);
  padding: 8px 12px;
  border-radius: 6px;
  font-size: 13px;
  max-width: 200px;
  margin: 0;
  border: none;
}
.anchor-note {
  margin-top: 40px;
  position: relative;
}
.note-marker {
  color: rgb(220, 53, 69);
  font-weight: 700;
  cursor: help;
}
.note-content {
  position: fixed;
  position-anchor: --note-marker;
  top: anchor(bottom);
  left: anchor(right);
  translate: 4px 4px;
  background-color: rgb(255, 243, 205);
  padding: 8px 12px;
  border: 1px solid rgb(255, 193, 7);
  border-radius: 4px;
  font-size: 12px;
  max-width: 200px;
}

